#include <stdio.h>
#include <math.h>
#define MOD 1000000007

long long gcd(long long a, long long b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

long long phi(long long n) {
    long long result = n;
    for (long long i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            while (n % i == 0) n /= i;
            result -= result / i;
        }
    }
    if (n > 1) result -= result / n;
    return result;
}

long long powMod(long long a, long long b, long long mod) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % mod;
        a = (a * a) % mod;
        b >>= 1;
    }
    return res;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N, K;
        scanf("%lld %lld", &N, &K);
        long long sum = 0;
        for (long long i = 1; i <= N; i++) {
            if (gcd(i, N) == 1) {
                sum = (sum + powMod(i, K, MOD)) % MOD;
            }
        }
        printf("%lld\n", sum);
    }
    return 0;
}

