def gcd(a, b):
    if b == 0: return a
    return gcd(b, a % b)

def phi(n):
    result = n
    for i in range(2, int(math.sqrt(n)) + 1):
        if n % i == 0:
            while n % i == 0: n //= i
            result -= result // i
    if n > 1: result -= result // n
    return result

def powMod(a, b, mod):
    res = 1
    while b > 0:
        if b % 2 == 1: res = (res * a) % mod
        a = (a * a) % mod
        b >>= 1
    return res

